  "inlineSchema": "// Schema do banco — 3aq Talent\n// Cada entidade tem comentários em português explicando o que guarda.\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"postgresql\"\n  url      = env(\"DATABASE_URL\")\n}\n\nenum Role {\n  CANDIDATO\n  RECRUTADOR\n}\n\nenum JobStatus {\n  ABERTA\n  ENCERRADA\n  RASCUNHO\n}\n\nenum ApplicationStatus {\n  INSCRITO\n  EM_ANALISE\n  APROVADO\n  REPROVADO\n}\n\nenum ChallengeType {\n  MULTIPLA_ESCOLHA\n  CODIGO_JS\n}\n\n// ----------- Usuário (Candidato ou Recrutador) -----------\nmodel User {\n  id          String   @id @default(cuid())\n  nome        String\n  email       String   @unique\n  senha       String\n  role        Role     @default(CANDIDATO)\n  github      String?\n  bio         String?\n  avatar      String?\n  aceitouLGPD Boolean  @default(false)\n  ativo       Boolean  @default(true)\n  createdAt   DateTime @default(now())\n  updatedAt   DateTime @updatedAt\n\n  // relações\n  resumes        Resume[]\n  applications   Application[]\n  submissions    Submission[]\n  githubAnalysis GithubAnalysis?\n  jobsCriadas    Job[]           @relation(\"RecrutadorJobs\")\n  auditLogs      AuditLog[]\n  refreshTokens  RefreshToken[]\n}\n\n// ----------- Token de refresh (para manter login seguro) -----------\nmodel RefreshToken {\n  id        String   @id @default(cuid())\n  token     String   @unique\n  userId    String\n  user      User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n  expiresAt DateTime\n  createdAt DateTime @default(now())\n}\n\n// ----------- Vaga -----------\nmodel Job {\n  id           String    @id @default(cuid())\n  titulo       String\n  descricao    String\n  tecnologias  String[]\n  senioridade  String    @default(\"PLENO\")\n  status       JobStatus @default(ABERTA)\n  recrutadorId String\n  recrutador   User      @relation(\"RecrutadorJobs\", fields: [recrutadorId], references: [id], onDelete: Cascade)\n  createdAt    DateTime  @default(now())\n  updatedAt    DateTime  @updatedAt\n\n  challenges   Challenge[]\n  applications Application[]\n}\n\n// ----------- Currículo -----------\nmodel Resume {\n  id            String   @id @default(cuid())\n  candidatoId   String\n  candidato     User     @relation(fields: [candidatoId], references: [id], onDelete: Cascade)\n  arquivo       String // caminho do PDF salvo (criptografado)\n  nomeArquivo   String\n  textoExtraido String   @db.Text\n  createdAt     DateTime @default(now())\n}\n\n// ----------- Inscrição em uma vaga -----------\nmodel Application {\n  id             String            @id @default(cuid())\n  candidatoId    String\n  candidato      User              @relation(fields: [candidatoId], references: [id], onDelete: Cascade)\n  vagaId         String\n  vaga           Job               @relation(fields: [vagaId], references: [id], onDelete: Cascade)\n  status         ApplicationStatus @default(INSCRITO)\n  notaFinal      Float             @default(0)\n  scoreCurriculo Float             @default(0)\n  scoreGithub    Float             @default(0)\n  scoreDesafios  Float             @default(0)\n  resumoIA       String?           @db.Text\n  feedback       String?           @db.Text\n  createdAt      DateTime          @default(now())\n  updatedAt      DateTime          @updatedAt\n\n  submissions Submission[]\n\n  @@unique([candidatoId, vagaId])\n}\n\n// ----------- Desafio (questão ou código JS) -----------\nmodel Challenge {\n  id              String        @id @default(cuid())\n  vagaId          String\n  vaga            Job           @relation(fields: [vagaId], references: [id], onDelete: Cascade)\n  tipo            ChallengeType\n  enunciado       String        @db.Text\n  // se for múltipla escolha:\n  alternativas    Json? // [{id:'a', texto:'...'}, ...]\n  respostaCorreta String?\n  // se for código JS:\n  exemplos        Json? // [{entrada:[1,2], saida:3}]\n  casosTeste      Json? // [{entrada:[2,3], saidaEsperada:5}, ...]\n  peso            Int           @default(1)\n  createdAt       DateTime      @default(now())\n\n  submissions Submission[]\n}\n\n// ----------- Resposta do candidato a um desafio -----------\nmodel Submission {\n  id            String       @id @default(cuid())\n  challengeId   String\n  challenge     Challenge    @relation(fields: [challengeId], references: [id], onDelete: Cascade)\n  candidatoId   String\n  candidato     User         @relation(fields: [candidatoId], references: [id], onDelete: Cascade)\n  applicationId String?\n  application   Application? @relation(fields: [applicationId], references: [id], onDelete: SetNull)\n  codigo        String?      @db.Text // código submetido (se for JS)\n  resposta      String? // alternativa marcada (se for múltipla escolha)\n  nota          Float        @default(0)\n  detalhes      Json? // resultado de cada caso de teste\n  createdAt     DateTime     @default(now())\n}\n\n// ----------- Análise do GitHub -----------\nmodel GithubAnalysis {\n  id              String    @id @default(cuid())\n  candidatoId     String    @unique\n  candidato       User      @relation(fields: [candidatoId], references: [id], onDelete: Cascade)\n  username        String\n  score           Float\n  repositorios    Int\n  estrelas        Int\n  seguidores      Int\n  tecnologias     String[]\n  ultimaAtividade DateTime?\n  createdAt       DateTime  @default(now())\n  updatedAt       DateTime  @updatedAt\n}\n\n// ----------- Logs de auditoria (LGPD) -----------\nmodel AuditLog {\n  id        String   @id @default(cuid())\n  userId    String?\n  user      User?    @relation(fields: [userId], references: [id], onDelete: SetNull)\n  acao      String\n  entidade  String?\n  detalhes  Json?\n  ip        String?\n  createdAt DateTime @default(now())\n}\n",
  "inlineSchemaHash": "5a2821d5c21b511aa446e12b52b3211e01e3d0a1198f2b90e8b2bae442630109",
